const ANIMALITOS = {
  "0": "Delfin", "00": "Ballena", "1": "Carnero", "2": "Toro",
  "3": "Ciempies", "4": "Alacran", "5": "Leon", "6": "Rana",
  "7": "Perico", "8": "Raton", "9": "Aguila", "10": "Tigre",
  "11": "Gato", "12": "Caballo", "13": "Mono", "14": "Paloma",
  "15": "Zorro", "16": "Oso", "17": "Pavo", "18": "Burro",
  "19": "Chivo", "20": "Cochino", "21": "Gallo", "22": "Camello",
  "23": "Cebra", "24": "Iguana", "25": "Gallina", "26": "Vaca",
  "27": "Perro", "28": "Zamuro", "29": "Elefante", "30": "Caiman",
  "31": "Lapa", "32": "Ardilla", "33": "Pescado", "34": "Venado",
  "35": "Jirafa", "36": "Culebra"
};

const items = $input.all();
const resultados = [];

for (const item of items) {
  const html = item.json.data || item.json.body || "";

  // 1. Extraer fecha del datepicker o del tГӯtulo
  let fechaPagina = "";
  const fechaMatch = html.match(/id="datepicker"[^>]*value="(\d{4}-\d{2}-\d{2})"/);
  if (fechaMatch) {
    fechaPagina = fechaMatch[1];
  } else {
    const tituloMatch = html.match(/el dia <strong>(\d{1,2}) de ([a-z]+) de (\d{4})/i);
    if (tituloMatch) {
      const meses = {enero:'01',febrero:'02',marzo:'03',abril:'04',mayo:'05',junio:'06',
                     julio:'07',agosto:'08',septiembre:'09',octubre:'10',noviembre:'11',diciembre:'12'};
      const mes = meses[tituloMatch[2].toLowerCase()];
      if (mes) fechaPagina = `${tituloMatch[3]}-${mes}-${tituloMatch[1].padStart(2,'0')}`;
    }
  }
  if (!fechaPagina) continue; // Saltar si no hay fecha

  // 2. Buscar todos los bloques de sorteos manualmente (contando profundidad de divs)
  const inicioBloque = '<div class="col-sm-6 col-md-4 col-lg-16 mb-5">';
  let pos = 0;
  while ((pos = html.indexOf(inicioBloque, pos)) !== -1) {
    const start = pos + inicioBloque.length;
    // Encontrar el cierre del div principal (al mismo nivel)
    let depth = 1;
    let end = start;
    while (depth > 0 && end < html.length) {
      const nextOpen = html.indexOf('<div', end);
      const nextClose = html.indexOf('</div>', end);
      if (nextClose === -1) break;
      if (nextOpen !== -1 && nextOpen < nextClose) {
        depth++;
        end = nextOpen + 4; // avanzar despuГ©s de '<div'
      } else {
        depth--;
        end = nextClose + 6; // avanzar despuГ©s de '</div>'
      }
    }
    const bloque = html.substring(start, end - 6); // contenido sin el </div> final
    pos = end;

    // 3. Extraer nГәmero y animal del <h4>
    const h4Match = bloque.match(/<h4[^>]*>(\d{1,2}|00)\s+([a-zA-ZГЎГ©ГӯГіГәГұ]+)<\/h4>/i);
    if (!h4Match) continue;
    const numero = h4Match[1];
    const animalNombre = ANIMALITOS[numero] || h4Match[2];

    // 4. Extraer hora del <h5>
    const h5Match = bloque.match(/<h5[^>]*>(?:Lotto Activo\s*)?(\d{1,2}:\d{2}\s*[AP]M)/i);
    if (!h5Match) continue;
    const hora = h5Match[1].toUpperCase();

    // 5. Determinar franja horaria
    let franja = "tarde";
    const h = parseInt(hora.split(":")[0]);
    if (hora.includes("AM")) franja = "maГұana";
    else if (h >= 5 && h !== 12) franja = "noche";

    resultados.push({
      json: {
        loteria: "Lotto Activo",
        fecha: fechaPagina,
        hora: hora,
        franja: franja,
        numero: numero,
        animal: animalNombre
      }
    });
  }
}

// 6. Ordenar por fecha y hora (ascendente: antiguo вҶ’ reciente)
resultados.sort((a, b) => {
  const dateA = new Date(`${a.json.fecha} ${a.json.hora.replace(/(AM|PM)/, ' $1')}`);
  const dateB = new Date(`${b.json.fecha} ${b.json.hora.replace(/(AM|PM)/, ' $1')}`);
  return dateA - dateB;
});

return resultados.length > 0 ? resultados : [{ json: { error: "No se encontraron datos reales." } }];

// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
// SETEAR ESTADГҚSTICAS вҖ” Lotto Activo (mejorado)
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

const items = $input.all();
let datos = items.map(i => i.json).filter(d => !d.error && d.fecha && d.hora && d.numero !== undefined);

if (datos.length === 0) {
  return [{ json: { error: 'No hay datos para procesar' } }];
}

// в”Җв”Җ Universo oficial Lotto Activo: 0, 00, 1-36 (38 nГәmeros) в”Җв”Җ
const UNIVERSO = ["0", "00", ...Array.from({length: 36}, (_, i) => (i + 1).toString())];
const N_UNIVERSO = UNIVERSO.length; // 38

// в”Җв”Җ FunciГіn para convertir hora a timestamp comparable в”Җв”Җ
function horaAMs(horaStr, fecha) {
  // Normaliza "8:00 AM", "08AM", "08:00AM", etc.
  const limpia = horaStr.trim().replace(/(\d)(AM|PM)/i, '$1 $2').replace(/\./g,'');
  return new Date(`${fecha} ${limpia}`);
}

// в”Җв”Җ 1. Ordenar ASCENDENTE (mГЎs antiguo primero) в”Җв”Җ
datos.sort((a, b) => horaAMs(a.hora, a.fecha) - horaAMs(b.hora, b.fecha));

// в”Җв”Җ 2. Frecuencias globales в”Җв”Җ
const frecNumero = {};
UNIVERSO.forEach(n => frecNumero[n] = 0);

datos.forEach(d => {
  const n = String(d.numero).trim();
  if (frecNumero.hasOwnProperty(n)) frecNumero[n]++;
});

// в”Җв”Җ 3. Top/Bottom (clonar para evitar mutaciГіn del mismo array) в”Җв”Җ
const entradasFrecuencia = Object.entries(frecNumero);

const top5 = [...entradasFrecuencia]
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5)
  .map(([num, veces]) => ({ numero: num, veces }));

const bottom5 = [...entradasFrecuencia]
  .filter(([, c]) => c > 0)          // excluye los que nunca salieron
  .sort((a, b) => a[1] - b[1])
  .slice(0, 5)
  .map(([num, veces]) => ({ numero: num, veces }));

const numerosInactivos = entradasFrecuencia
  .filter(([, c]) => c === 0)
  .map(([n]) => n);

const frecOrdenada = [...entradasFrecuencia]
  .filter(([, c]) => c > 0)
  .sort((a, b) => b[1] - a[1])
  .map(([num, count]) => `${num}:${count}`)
  .join(', ');

// в”Җв”Җ 4. DГӯas sin salir por nГәmero в”Җв”Җ
// Obtener la fecha mГЎs reciente en los datos
const fechaMax = datos[datos.length - 1].fecha;

// Para cada nГәmero, buscar la Гәltima vez que saliГі
const ultimaAparicion = {};
UNIVERSO.forEach(n => ultimaAparicion[n] = null);

datos.forEach(d => {
  const n = String(d.numero).trim();
  if (ultimaAparicion.hasOwnProperty(n)) {
    // Como estГЎ ordenado ASC, la Гәltima asignaciГіn es la mГЎs reciente
    ultimaAparicion[n] = d.fecha;
  }
});

const diasSinSalir = {};
UNIVERSO.forEach(n => {
  if (!ultimaAparicion[n]) {
    diasSinSalir[n] = 999; // nunca saliГі
  } else {
    const diff = new Date(fechaMax) - new Date(ultimaAparicion[n]);
    diasSinSalir[n] = Math.floor(diff / (1000 * 60 * 60 * 24));
  }
});

// Enjaulados ordenados por dГӯas sin salir (descendente)
const enjauladosTodos = UNIVERSO
  .map(n => ({ numero: n, dias: diasSinSalir[n] }))
  .filter(e => e.dias > 0)
  .sort((a, b) => b.dias - a.dias);

// Solo los crГӯticos (>5 dГӯas) para el prompt
const enjauladosCriticos = enjauladosTodos
  .filter(e => e.dias > 5)
  .map(e => `${e.numero}(${e.dias}d)`)
  .join(', ');

// Formato completo para el prompt (igual al original pero con dГӯas reales)
const enjauladosTexto = enjauladosTodos
  .map(e => `${e.numero}(${e.dias}d)`)
  .join(', ');

// в”Җв”Җ 5. Frecuencia por FRANJA horaria (maГұana/tarde/noche) в”Җв”Җ
const frecFranja = { maГұana: {}, tarde: {}, noche: {} };
Object.keys(frecFranja).forEach(f => {
  UNIVERSO.forEach(n => { frecFranja[f][n] = 0; });
});

datos.forEach(d => {
  const n = String(d.numero).trim();
  const f = d.franja;
  if (frecFranja[f] && frecFranja[f].hasOwnProperty(n)) {
    frecFranja[f][n]++;
  }
});

const frecHorariaTexto = Object.entries(frecFranja)
  .map(([franja, freq]) => {
    const top3 = Object.entries(freq)
      .filter(([, c]) => c > 0)
      .sort((a, b) => b[1] - a[1])
      .slice(0, 3)
      .map(([n, c]) => `${n}(${c}x)`)
      .join(', ');
    return `${franja}: top3=[${top3}]`;
  })
  .join(' | ');

// в”Җв”Җ 6. Frecuencia por HORA EXACTA (08AM, 09AM вҖҰ 07PM) в”Җв”Җ
const HORAS_EXACTAS = ["08AM","09AM","10AM","11AM","12PM","01PM","02PM","03PM","04PM","05PM","06PM","07PM"];

const frecHoraExacta = {};
HORAS_EXACTAS.forEach(h => {
  frecHoraExacta[h] = {};
  UNIVERSO.forEach(n => { frecHoraExacta[h][n] = 0; });
});

datos.forEach(d => {
  const n = String(d.numero).trim();
  // Normalizar hora al formato "08AM"
  const horaRaw = d.hora.trim().toUpperCase().replace(/\s/g,'').replace(':00','');
  const horaKey = horaRaw.replace(/^(\d)([AP]M)$/, '0$1$2'); // "8AM" вҶ’ "08AM"
  if (frecHoraExacta[horaKey] && frecHoraExacta[horaKey].hasOwnProperty(n)) {
    frecHoraExacta[horaKey][n]++;
  }
});

// Top 3 por hora exacta
const frecHoraExactaResumen = {};
HORAS_EXACTAS.forEach(h => {
  frecHoraExactaResumen[h] = Object.entries(frecHoraExacta[h])
    .filter(([, c]) => c > 0)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 3)
    .map(([n, c]) => `${n}(${c}x)`);
});

// в”Җв”Җ 7. Pares consecutivos вҖ” SOLO dentro del mismo dГӯa в”Җв”Җ
// CORRECCIГ“N CLAVE: el original cruzaba el Гәltimo sorteo del dГӯa N
// con el primero del dГӯa N+1, generando pares fantasma.
const pares = {};
for (let i = 0; i < datos.length - 1; i++) {
  // Solo contar si los dos sorteos son del mismo dГӯa
  if (datos[i].fecha === datos[i + 1].fecha) {
    const key = `${datos[i].numero}->${datos[i+1].numero}`;
    pares[key] = (pares[key] || 0) + 1;
  }
}

const paresSignificativos = Object.entries(pares)
  .filter(([, v]) => v >= 2)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 10)
  .map(([par, count]) => `${par}: ${count}x`)
  .join(', ') || 'Ninguno significativo';

// в”Җв”Җ 8. Serie temporal вҖ” orden MГҒS ANTIGUO вҶ’ mГЎs reciente (correcto para la IA) в”Җв”Җ
const CANT_SERIE = 50;
const serieTemporal = datos
  .slice(-CANT_SERIE)
  .map(d => d.numero)
  .join(', ');

// в”Җв”Җ 9. ChiВІ (correcto: grados de libertad = N_UNIVERSO - 1 = 37) в”Җв”Җ
const total = datos.length;
const esperado = total / N_UNIVERSO;
let chiCuadrado = 0;
Object.values(frecNumero).forEach(obs => {
  chiCuadrado += Math.pow(obs - esperado, 2) / (esperado || 1);
});

// ChiВІ crГӯtico para gl=37, p=0.05 вҶ’ 52.19
const CHI_CRITICO = 52.19;
const esAleatorio = chiCuadrado < CHI_CRITICO;

// в”Җв”Җ 10. BASELINE ALEATORIO в”Җв”Җ
// ВҝCuГЎntos aciertos obtiene una predicciГіn aleatoria de 12 nГәmeros
// comparada contra 12 resultados reales (uno por hora exacta)?
// MГ©trica honesta: acierto = mismo nГәmero en la misma posiciГіn/hora.
const SIMULACIONES = 10000;
let totalAciertosAleatorios = 0;

// Tomar los Гәltimos 12 sorteos reales como referencia
const ultimos12Reales = datos.slice(-12).map(d => String(d.numero));

for (let s = 0; s < SIMULACIONES; s++) {
  for (let pos = 0; pos < 12; pos++) {
    const aleatorio = UNIVERSO[Math.floor(Math.random() * N_UNIVERSO)];
    if (aleatorio === ultimos12Reales[pos]) totalAciertosAleatorios++;
  }
}

const tasaBaselineAleatorio = (totalAciertosAleatorios / (SIMULACIONES * 12));
const aciertosEsperadosPorDia = (tasaBaselineAleatorio * 12).toFixed(3);

// в”Җв”Җ 11. Fechas del rango в”Җв”Җ
const fechaInicio = datos[0]?.fecha;
const fechaFin    = datos[datos.length - 1]?.fecha;

// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
// OUTPUT
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
return [{
  json: {
    // Metadatos
    total_registros:        total,
    fecha_inicio:           fechaInicio,
    fecha_fin:              fechaFin,
    numeros_activos:        entradasFrecuencia.filter(([,c]) => c > 0).length,
    numeros_inexistentes:   numerosInactivos,

    // Para el prompt de la IA
    ultimos_resultados:     serieTemporal,          // orden: recienteвҶ’antiguo
    frecuencia_numeros:     frecOrdenada,
    frecuencia_horaria:     frecHorariaTexto,
    pares_consecutivos:     paresSignificativos,
    top5_mas_frecuentes:    top5,
    top5_menos_frecuentes:  bottom5,

    // Enjaulados
    enjaulados_todos:       enjauladosTexto,
    enjaulados_criticos:    enjauladosCriticos,     // solo >5 dГӯas

    // Nuevo: desglose por hora exacta
    frecuencia_hora_exacta: frecHoraExactaResumen,

    // ChiВІ
    chi_cuadrado:           chiCuadrado.toFixed(2),
    chi_grados_libertad:    N_UNIVERSO - 1,
    parece_aleatorio:       esAleatorio,
    nivel_aleatoriedad:     esAleatorio
                              ? 'Alto вҖ” distribuciГіn compatible con azar'
                              : 'Bajo вҖ” posible sesgo detectado',

    // Baseline (nuevo вҖ” para comparar contra la IA)
    baseline_tasa_acierto:          tasaBaselineAleatorio.toFixed(6),
    baseline_aciertos_esperados_dia: aciertosEsperadosPorDia,
    baseline_simulaciones:           SIMULACIONES
  }
}];

