// ============================================================
// Extraer predicciГіn de GPT 120B desde mensaje de Telegram
// VersiГіn robusta que maneja cualquier formato de lГӯneas
// ============================================================

// в”Җв”Җ 1. Obtener el texto del mensaje в”Җв”Җ
const inputData = $input.first().json;
const messageText = inputData.result?.text || inputData.text || '';

if (!messageText) {
  throw new Error('No se encontrГі texto del mensaje de Telegram');
}

// в”Җв”Җ 2. Extraer confianza в”Җв”Җ
const confianzaMatch = messageText.match(/рҹ“Ҳ Confianza:\s*(\d+)%/);
const confianza = confianzaMatch ? parseInt(confianzaMatch[1], 10) : 0;

// в”Җв”Җ 3. Extraer enjaulados usados в”Җв”Җ
const enjauladosMatch = messageText.match(/рҹҗҳ Enjaulados usados:\s*([\d,\s]+)/);
let enjaulados = [];
if (enjauladosMatch) {
  enjaulados = enjauladosMatch[1].split(',').map(s => s.trim()).filter(n => n);
}

// в”Җв”Җ 4. Extraer la secuencia de horas (mГ©todo robusto) в”Җв”Җ
// Buscar el bloque que contiene las horas: desde "рҹҺҜ SECUENCIA PREDICHA" hasta "рҹ“Ҳ Confianza"
let bloqueSecuencia = '';
const inicioSecuencia = messageText.indexOf('рҹҺҜ SECUENCIA PREDICHA');
if (inicioSecuencia === -1) {
  throw new Error('No se encontrГі el encabezado "рҹҺҜ SECUENCIA PREDICHA"');
}
const finSecuencia = messageText.indexOf('рҹ“Ҳ Confianza', inicioSecuencia);
if (finSecuencia === -1) {
  // Si no encuentra "рҹ“Ҳ Confianza", busca el siguiente "в•җв•җв•җв•җ" o el final
  const finAlternativo = messageText.indexOf('в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ', inicioSecuencia + 100);
  bloqueSecuencia = finAlternativo !== -1 
    ? messageText.substring(inicioSecuencia, finAlternativo)
    : messageText.substring(inicioSecuencia);
} else {
  bloqueSecuencia = messageText.substring(inicioSecuencia, finSecuencia);
}

// Extraer todas las lГӯneas con formato "08AM: 30" o "08AM:30"
