const razonamiento = razonamientoMatch ? razonamientoMatch[1].trim() : '';

// в”Җв”Җ 6. Contar horas vГЎlidas в”Җв”Җ
const horasValidas = Object.keys(secuencia).length;

// в”Җв”Җ 7. Generar salida para Supabase в”Җв”Җ
