if (!textoRespuesta || typeof textoRespuesta !== 'string') {
  throw new Error('No se encontrГі campo "text" vГЎlido en la entrada');
}

// в”Җв”Җ 2. Parsear el JSON interno в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
let datos;
try {
  datos = JSON.parse(textoRespuesta);
} catch (e) {
  throw new Error(`Error al parsear JSON: ${e.message}\nTexto: ${textoRespuesta.substring(0, 200)}`);
}

// в”Җв”Җ 3. Validar estructura mГӯnima в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
if (!datos.secuencia || typeof datos.secuencia !== 'object') {
  throw new Error('El JSON no contiene el campo "secuencia" o no es un objeto');
}

