  const num = parseFloat(c);
  if (isNaN(num)) return 0;
  // Si viene como 0.78 (entre 0 y 1) lo pasamos a porcentaje
  return num <= 1 ? Math.round(num * 100) : Math.round(num);
})();

const logica = datos.logica || '';
const razonamiento = datos.razonamiento_paso_a_paso || '';

// в”Җв”Җ 6. Contar cuГЎntas horas tienen valor real (no '-') в”Җв”Җ
const horasValidas = HORAS.filter(h => secuenciaNormalizada[h] !== '-').length;

